{{
  (() => {
    const item = Custom1.model.itemSeleccionado;
    const loteSeleccionado = tbl_ofertas.selectedRow;
    const cantidad = Number(inp_cantidad_compra.text || 0);
    const config = Leer_Config_Tienda.data[0];
    const margen = Number(config?.margen_ganancia_default || 0.10);

    if (!item || cantidad <= 0) return "0 ISK";

    // 🛡️ Blindaje de precio: 
    // 1. Buscamos el precio calculado en la fila de la tabla
    // 2. Si no hay selección, usamos el precio que trajo la vitrina
    // 3. Si todo falla, calculamos manualmente sobre el precio base
    let precioParaCalculo = Number(loteSeleccionado?.precio_cliente || item?.precio_cliente || 0);

    if (precioParaCalculo === 0) {
      const precioBase = Number(item.mejor_precio || item.precio_isk || 0);
      precioParaCalculo = precioBase * (1 + margen);
    }

    const subtotal = cantidad * precioParaCalculo;

    return Math.round(subtotal).toLocaleString('en-US') + " ISK";
  })()
}}
